-- Consolidated historical price import for 2023, part 2 of 8
-- Provider: TBANK

-- Generated by scripts/tbank_history/generate_prices_sql.sh
-- Year: 2023
-- Provider: TBANK
-- Rows: 374348

BEGIN;
CREATE TEMP TABLE stg_tbank_prices_src (
    db_code text NOT NULL,
    trade_date date NOT NULL,
    price numeric(18,8) NOT NULL
) ON COMMIT DROP;

;

;

;

;

;


-- Diagnostics for this chunk
WITH unresolved AS (
    SELECT s.db_code, s.trade_date
    FROM stg_tbank_prices_src s
    LEFT JOIN LATERAL (
        SELECT 1
        FROM instruments instrument
        WHERE upper(coalesce(instrument.figi, '')) = upper(s.db_code)
           OR upper(coalesce(instrument.ticker, '')) = upper(s.db_code)
           OR upper(coalesce(instrument.isin, '')) = upper(s.db_code)
           OR EXISTS (
               SELECT 1
               FROM instrument_aliases ia
               WHERE ia.instrument_id = instrument.id
                 AND upper(ia.normalized_alias_code) = upper(s.db_code)
           )
        LIMIT 1
    ) i ON true
    WHERE i IS NULL
)
SELECT count(*) AS unresolved_rows FROM unresolved;

WITH resolved AS (
    SELECT
        i.id AS instrument_id,
        s.trade_date
    FROM stg_tbank_prices_src s
    JOIN LATERAL (
        SELECT instrument.id
        FROM instruments instrument
        WHERE upper(coalesce(instrument.figi, '')) = upper(s.db_code)
           OR upper(coalesce(instrument.ticker, '')) = upper(s.db_code)
           OR upper(coalesce(instrument.isin, '')) = upper(s.db_code)
           OR EXISTS (
               SELECT 1
               FROM instrument_aliases ia
               WHERE ia.instrument_id = instrument.id
                 AND upper(ia.normalized_alias_code) = upper(s.db_code)
           )
        ORDER BY
            CASE WHEN upper(coalesce(instrument.figi, '')) = upper(s.db_code) THEN 0 ELSE 1 END,
            CASE WHEN upper(coalesce(instrument.ticker, '')) = upper(s.db_code) THEN 0 ELSE 1 END,
            CASE WHEN upper(coalesce(instrument.isin, '')) = upper(s.db_code) THEN 0 ELSE 1 END,
            instrument.created_at
        LIMIT 1
    ) i ON TRUE
)
SELECT count(*) AS duplicate_rows
FROM (
    SELECT instrument_id, trade_date, count(*) AS cnt
    FROM resolved
    GROUP BY instrument_id, trade_date
    HAVING count(*) > 1
) d;

CREATE TEMP TABLE stg_tbank_prices_resolved ON COMMIT DROP AS
WITH resolved AS (
    SELECT
        i.id AS instrument_id,
        src.trade_date,
        src.price::numeric(18,4) AS price,
        i.currency_id,
        md5(i.id::text || '|' || src.trade_date::text || '|TBANK') AS hash_key
    FROM stg_tbank_prices_src src
    JOIN LATERAL (
        SELECT instrument.*
        FROM instruments instrument
        WHERE upper(coalesce(instrument.figi, '')) = upper(src.db_code)
           OR upper(coalesce(instrument.ticker, '')) = upper(src.db_code)
           OR upper(coalesce(instrument.isin, '')) = upper(src.db_code)
           OR EXISTS (
               SELECT 1
               FROM instrument_aliases ia
               WHERE ia.instrument_id = instrument.id
                 AND upper(ia.normalized_alias_code) = upper(src.db_code)
           )
        ORDER BY
            CASE WHEN upper(coalesce(instrument.figi, '')) = upper(src.db_code) THEN 0 ELSE 1 END,
            CASE WHEN upper(coalesce(instrument.ticker, '')) = upper(src.db_code) THEN 0 ELSE 1 END,
            CASE WHEN upper(coalesce(instrument.isin, '')) = upper(src.db_code) THEN 0 ELSE 1 END,
            instrument.created_at
        LIMIT 1
    ) i ON TRUE
)
SELECT
    instrument_id,
    trade_date,
    price,
    currency_id,
    hash_key
FROM resolved;

WITH upserted AS (
    SELECT
        (
            substr(hash_key, 1, 8) || '-' ||
            substr(hash_key, 9, 4) || '-' ||
            substr(hash_key, 13, 4) || '-' ||
            substr(hash_key, 17, 4) || '-' ||
            substr(hash_key, 21, 12)
        )::uuid,
        instrument_id,
        (trade_date::timestamp AT TIME ZONE 'UTC'),
        price,
        currency_id,
        'TBANK',
        now(),
        now()
    FROM stg_tbank_prices_resolved
    ON CONFLICT (instrument_id, date, provider)
    DO UPDATE
    SET value = EXCLUDED.value,
        currency_id = EXCLUDED.currency_id,
        updated_at = now()
    RETURNING instrument_id
)
SELECT count(*) FROM upserted;
COMMIT;

DO $$
DECLARE
    expected_moex bigint := 37461;
    expected_tbank bigint := 374348;
    actual_moex bigint;
    actual_tbank bigint;
    actual_total bigint;
BEGIN
    WITH scoped AS (
        SELECT provider, count(*) AS rows_count
        FROM prices
        WHERE date >= TIMESTAMP '2023-01-01 00:00:00+00'
          AND date < TIMESTAMP '2024-01-01 00:00:00+00'
          AND upper(provider) IN ('MOEX', 'TBANK')
        GROUP BY provider
    )
    SELECT
        COALESCE(max(CASE WHEN upper(provider) = 'MOEX' THEN rows_count END), 0),
        COALESCE(max(CASE WHEN upper(provider) = 'TBANK' THEN rows_count END), 0),
        COALESCE(sum(rows_count), 0)
    INTO actual_moex, actual_tbank, actual_total
    FROM scoped;

    IF actual_moex <> expected_moex THEN
        RAISE EXCEPTION 'Consolidated 2023 validation failed: expected MOEX %, got %.', expected_moex, actual_moex;
    END IF;

    IF actual_tbank <> expected_tbank THEN
        RAISE EXCEPTION 'Consolidated 2023 validation failed: expected TBANK %, got %.', expected_tbank, actual_tbank;
    END IF;

    IF actual_total <> expected_moex + expected_tbank THEN
        RAISE EXCEPTION 'Consolidated 2023 validation failed: expected total %, got %.', expected_moex + expected_tbank, actual_total;
    END IF;

    RAISE NOTICE 'Consolidated 2023 validation passed. MOEX: %, TBANK: %, total: %.', actual_moex, actual_tbank, actual_total;
END $$;
